(function  (){function  ensureDropdownStyles(){var  href='/assets/css/header-dropdowns.css';var  already=document.querySelector('link[href="'+href+'"]');if  (!already){var  link=document.createElement('link');link.rel='stylesheet';link.href=href;document.head.appendChild(link);}if  (document.getElementById('header-dropdowns-critical'))return ;var  style=document.createElement('style');style.id='header-dropdowns-critical';style.textContent='.home-header__dropdown{position:absolute;visibility:hidden;opacity:0;pointer-events:none}'+'.home-mobile-menu[hidden]{display:none!important}';document.head.appendChild(style);}function  ensureDropdownScript(){var  src='/assets/js/header-dropdowns.js';var  already=document.querySelector('script[src="'+src+'"]');if  (already)return ;var  script=document.createElement('script');script.src=src;script.defer=true;document.head.appendChild(script);}function  init(){var  placeholder=document.getElementById('header-placeholder');if  (!placeholder)return ;ensureDropdownStyles();fetch('/partials/header.html').then(function  (response){if  (!response.ok)throw new Error('HTTP '+response.status);return  response.text();}).then(function  (html){placeholder.innerHTML=html;wireHeader(placeholder);ensureDropdownScript();}).catch(function  (error){console.error('Header load error:',error);});}function  wireHeader(scope){var  header=scope.querySelector('.home-header');if  (!header)return ;var  toggle=scope.querySelector('#home-menu-toggle');var  menu=scope.querySelector('#home-mobile-menu');function  openMenu(){if  (!toggle||!menu)return ;header.classList.add('is-open');toggle.setAttribute('aria-expanded','true');toggle.setAttribute('aria-label','Close menu');menu.hidden=false;}function  closeMenu(){if  (!toggle||!menu)return ;header.classList.remove('is-open');toggle.setAttribute('aria-expanded','false');toggle.setAttribute('aria-label','Open menu');menu.hidden=true;}var  infobar=document.getElementById('home-infobar');var  lastScrollY=window.scrollY;var  HIDE_THRESHOLD=80;var  SHOW_THRESHOLD_DELTA=30;function  applyInfobarVisibility(){if  (!infobar)return ;if  (window.innerWidth<=900){infobar.style.display='none';header.style.top='0';}else  {infobar.style.display='';header.style.top='';}}applyInfobarVisibility();window.addEventListener('resize',applyInfobarVisibility);function  handleScroll(){var  y=window.scrollY;var  goingDown=y>lastScrollY;var  delta=Math.abs(y-lastScrollY);if  (y>20){header.classList.add('is-scrolled');}else  {header.classList.remove('is-scrolled');}if  (infobar&&window.innerWidth>900){if  (y<=4){infobar.classList.remove('is-hidden');}else  if  (goingDown&&y>HIDE_THRESHOLD){infobar.classList.add('is-hidden');}else  if  (!goingDown&&delta>SHOW_THRESHOLD_DELTA){infobar.classList.remove('is-hidden');}}lastScrollY=y;}if  (toggle&&menu){toggle.addEventListener('click',function  (event){event.preventDefault();event.stopPropagation();if  (header.classList.contains('is-open')){closeMenu();}else  {openMenu();}});document.addEventListener('click',function  (event){if  (!header.classList.contains('is-open'))return ;if  (!menu.contains(event.target)&&!toggle.contains(event.target)){closeMenu();}});window.addEventListener('resize',function  (){if  (window.innerWidth>900&&header.classList.contains('is-open')){closeMenu();}});closeMenu();}handleScroll();window.addEventListener('scroll',handleScroll,{passive:true});var  active=(document.body&&document.body.getAttribute('data-nav-active'))||'';if  (active){var  links=scope.querySelectorAll('[data-nav="'+active+'"]');Array.prototype.forEach.call(links,function  (link){link.setAttribute('aria-current','page');});}}if  (document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else  {init();}})();